namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_BYTES = 32;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Ca6k00597CustomTilingData tiling;

    const gert::StorageShape *inputShape = context->GetInputShape(0);
    const uint32_t totalLength =
        static_cast<uint32_t>(inputShape->GetOriginShape().GetShapeSize());
    const gert::Shape &originShape = inputShape->GetOriginShape();
    const uint32_t channels = static_cast<uint32_t>(originShape.GetDim(1));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int64_t *groupsAttr = attrs->GetAttrPointer<int64_t>(0);
    const uint32_t groups = static_cast<uint32_t>(*groupsAttr);

    uint32_t maxTile = UB_BUDGET_BYTES / (4 * sizeof(float));
    if (channels > 0) {
        maxTile = AlignDown(maxTile, channels);
    }
    if (maxTile < channels) {
        maxTile = channels;
    }

    uint32_t tileLen = maxTile;
    if (totalLength < tileLen) {
        tileLen = AlignDown(totalLength, channels);
        if (tileLen == 0) tileLen = totalLength;
    }

    uint32_t numTiles = (tileLen == 0) ? 1u : CeilDiv(totalLength, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 1u) blockDim = 1u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_groups(groups);
    tiling.set_channels(channels);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

